  receiptDateFilter: 'all',
  receiptCollectedFilter: 'all',
  receiptSortBy: 'newest',
  
  // Audit Log Filters & Pagination
  auditSearch: '',
  auditActionFilter: 'all',
  auditCategoryFilter: 'all',
  auditSeverityFilter: 'all',
  auditUserFilter: 'all',
  auditDateFrom: '',
  auditDateTo: '',
  auditPage: 1,
  auditPageSize: 25,

  // Delivery dashboard (Delivery role)
