function getTodayDateString() {
  const d = new Date();
  return new Date(d.getTime() - (d.getTimezoneOffset() * 60000)).toISOString().split('T')[0];
}

function t(key) {
  const lang = translations[state.language] || translations['en'];
  return lang[key] || key;
}

